import React from "react";

const MisionSection = () => {
  return (
    <section
      style={{
        display: "flex",
        maxWidth: "1200px",
        margin: "0 auto 5rem",
        gap: "2rem",
        alignItems: "center",
        flexWrap: "wrap",
        padding: "0 1rem",
      }}
    >
      {/* Texto a la izquierda */}
      <div style={{ flex: 1, minWidth: "300px" }}>
        <h3
          style={{
            textTransform: "uppercase",
            color: "#00509e",
            marginBottom: "0.5rem",
          }}
        >
          The Hero
        </h3>
        <h2
          style={{
            fontWeight: "900",
            fontSize: "2.25rem",
            marginBottom: "1rem",
            color: "#003E73",
          }}
        >
          Electrolytes, suit up
        </h2>
        <p
          style={{
            fontSize: "1.15rem",
            lineHeight: "1.6",
            color: "#003E73",
          }}
        >
          What do you do when your back’s against the wall? You get to work. Jai dropped
          out of business school, invested his tuition money, and John threw on his lab
          coat and experimented to launch our first flavor of Hydrant. And we haven't
          stopped since. Take that dehydration.
        </p>
      </div>

      {/* Imagen a la derecha */}
      <div style={{ flex: 1, minWidth: "300px" }}>
        <img
          src={require("../../assets/quien-contra-nosotros.jpg")}
          alt="Founders of Hydrant"
          style={{ width: "100%", borderRadius: "1rem" }}
        />
      </div>
    </section>
  );
};

export default MisionSection;
